mapper.sql:
FROM alert a
LEFT JOIN panel p ON p.panel_id = a.panel_id
LEFT JOIN circuit c ON c.circuit_id = a.circuit_id


        AND a.status = #{status}


        AND a.type = #{type}


        AND p.site_id = #{siteId}


        AND a.triggered_at >= #{fromAt}


        AND a.triggered_at < #{toAt}


        AND EXISTS (
            SELECT 1
            FROM user_site us
            WHERE us.user_id = #{userId}
              AND us.site_id = p.site_id
              AND us.deleted_at IS NULL
        )

FROM alert a
LEFT JOIN panel p ON p.panel_id = a.panel_id
LEFT JOIN site s ON s.site_id = p.site_id
LEFT JOIN circuit c ON c.circuit_id = a.circuit_id
LEFT JOIN `user` confirmer ON confirmer.user_id = a.confirmed_by


        AND a.status = #{status}


        AND a.type = #{type}


        AND p.site_id = #{siteId}


        AND a.triggered_at >= #{fromAt}


        AND a.triggered_at < #{toAt}


        AND a.alert_id IN

            #{alertId}



        AND EXISTS (
            SELECT 1
            FROM user_site us
            WHERE us.user_id = #{userId}
              AND us.site_id = p.site_id
              AND us.deleted_at IS NULL
        )

mapper.update:
UPDATE alert
SET status = 'RESOLVED',
    resolved_at = CURRENT_TIMESTAMP,
    resolution_note = #{resolutionNote}
WHERE alert_id = #{alertId}
  AND status = 'CONFIRMED'

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM alert
    WHERE panel_id = #{panelId}
      AND source = #{source}
      AND type = #{type}
      AND status IN ('UNCONFIRMED', 'CONFIRMED')
)

SELECT EXISTS(
    SELECT 1
    FROM alert
    WHERE circuit_id = #{circuitId}
      AND source = #{source}
      AND type = #{type}
      AND status IN ('UNCONFIRMED', 'CONFIRMED')
)

SELECT site_id
FROM panel
WHERE panel_id = #{panelId}
